        CREATE View [SSRS].[CountyCricketBoard_SeasonCurrLast_STD_Pivot]  as  With A As   (     SELECT Home_County_ID    ,Home_County_Name    ,Year_of_Fixture    ,Cast(isnull([No Result],0)    +isnull(Win,0)    +isnull([Abandoned] ,0)     +isnull([Cancelled] ,0)     +isnull([Conceded] ,0)     +isnull([InProgress],0) as numeric(8,2))  as Completed    ,Cast(isnull(Win,0) + isnull([No Result],0) + isnull(InProgress,0) as numeric(8,2))  as [1. Played]    ,isnull(cast([Abandoned] as numeric(8,2)),0) [3. Abandoned]    ,isnull(cast([Cancelled] as numeric(8,2)),0) [2. Cancelled]    ,isnull(cast([Conceded]  as numeric(8,2)),0)  [4. Conceded]    ,isnull(cast([ShortSided]as numeric(8,2)),0) [5. ShortSided]    FROM SSRS.CountyCricketBoard_SeasonCurrLast_STD  )      SELECT *  FROM   (  Select     Home_County_ID    ,Home_County_Name    ,Year_of_Fixture    --,Completed    ,[1. Played] /Completed [1. Played]    ,[2. Cancelled] /Completed [2. Cancelled]    ,[4. Conceded]  /Completed [4. Conceded]    ,[3. Abandoned] /Completed [3. Abandoned]    ,[5. ShortSided]/Completed [5. ShortSided]  FROM A  )TBL  UNPIVOT(CountofFixtures FOR category IN (     --[Completed]     [1. Played]     ,[3. Abandoned]     ,[2. Cancelled]     ,[4. Conceded]     ,[5. ShortSided]     )) B      